import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Order } from '../../data/models';

interface AccountBar {
  name: string;
  value: number;
  pct: number;
}

@Component({
  selector: 'app-orders',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './orders.component.html',
  styleUrl: './orders.component.css',
})
export class OrdersComponent {
  readonly statuses: (Order['status'] | 'all')[] = ['all', 'confirmed', 'in-production', 'shipped', 'delivered'];
  statusFilter = signal<Order['status'] | 'all'>('all');

  totalBacklog = computed(() => this.seed.orders().reduce((sum, o) => sum + o.amount, 0));
  inProduction = computed(() => this.seed.orders().filter((o) => o.status === 'in-production').length);
  slippingOrders = computed(() => this.seed.orders().filter((o) => o.slippage));
  slippingCount = computed(() => this.slippingOrders().length);
  onTimePct = computed(() => {
    const total = this.seed.orders().length;
    if (total === 0) return 100;
    const onTime = total - this.slippingCount();
    return Math.round((onTime / total) * 100);
  });

  filteredOrders = computed(() => {
    const f = this.statusFilter();
    if (f === 'all') return this.seed.orders();
    return this.seed.orders().filter((o) => o.status === f);
  });

  accountBars = computed<AccountBar[]>(() => {
    const map = new Map<string, number>();
    for (const o of this.seed.orders()) {
      map.set(o.accountName, (map.get(o.accountName) ?? 0) + o.amount);
    }
    const rows = Array.from(map.entries()).map(([name, value]) => ({ name, value, pct: 0 }));
    const max = Math.max(1, ...rows.map((r) => r.value));
    rows.forEach((r) => (r.pct = Math.round((r.value / max) * 100)));
    return rows.sort((a, b) => b.value - a.value);
  });

  setStatus(status: Order['status'] | 'all'): void {
    this.statusFilter.set(status);
  }

  statusBadge(status: Order['status']): string {
    switch (status) {
      case 'confirmed': return 'badge-info';
      case 'in-production': return 'badge-warning';
      case 'shipped': return 'badge-success';
      case 'delivered': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  constructor(public seed: SeedService) {}
}
